<h1 class="h5"><?= $funcionalidad ? 'Editar' : 'Crear' ?> funcionalidad</h1><form method="POST" class="row g-2"><?= csrf_campo() ?><div class="col-md-4"><input class="form-control" name="nombre" placeholder="Nombre" value="<?= e($funcionalidad['nombre'] ?? '') ?>" required></div><div class="col-md-4"><input class="form-control" name="codigo_interno" placeholder="Código interno" value="<?= e($funcionalidad['codigo_interno'] ?? '') ?>" required></div><div class="col-md-4"><select class="form-select" name="tipo_valor"><option value="booleano">Booleano</option><option value="numerico" <?= (($funcionalidad['tipo_valor'] ?? '')==='numerico')?'selected':'' ?>>Numérico</option><option value="ilimitado" <?= (($funcionalidad['tipo_valor'] ?? '')==='ilimitado')?'selected':'' ?>>Ilimitado</option></select></div><div class="col-md-8"><input class="form-control" name="descripcion" placeholder="Descripción" value="<?= e($funcionalidad['descripcion'] ?? '') ?>"></div><div class="col-md-4"><select class="form-select" name="estado"><option value="activo">Activo</option><option value="inactivo" <?= (($funcionalidad['estado'] ?? '')==='inactivo')?'selected':'' ?>>Inactivo</option></select></div><div class="col-12"><button class="btn btn-primary btn-sm">Guardar</button></div></form>
